package com.evolua.subscription.application; import com.evolua.subscription.domain.Subscription; import com.evolua.subscription.domain.SubscriptionRepository; import java.time.Instant; import java.util.List; import org.springframework.stereotype.Service; @Service public class SubscriptionService { private final SubscriptionRepository repository; public SubscriptionService(SubscriptionRepository repository) { this.repository = repository; } public Subscription create(String userId, String planCode, String status, String billingCycle, Boolean premium) { return repository.save(new Subscription(null, userId, planCode, status, billingCycle, premium, Instant.now())); } public List<Subscription> list(String userId) { return repository.findAllByUserId(userId); } }
